import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS
        String safeUserInput = sanitizeInput(userInput);

        String output = "<html><body>User input: " + safeUserInput + "</body></html>";

        PrintWriter out = response.getWriter();
        out.println(output);
    }

    private String sanitizeInput(String input) {
        // Implement your own sanitization logic here based on your requirements
        // This is just a basic example, you should use a more robust approach

        if (input == null) {
            return "";
        }

        return input.replaceAll("<", "&lt;").replaceAll(">", "&gt;");
    }
}

